   373→            <ArrowRight className="h-3.5 w-3.5 opacity-0 -translate-x-1 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
   374→          </Link>
   375→          {project.description && (
   376→            <p
   377→              className="mt-0.5 text-[13px] truncate"
   378→              style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
   379→            >
   380→              {project.description}
   381→            </p>
   382→          )}
   383→        </div>
   384→      </div>
   385→
   386→      {/* Content columns: sources | recent releases | semantic releases */}
   387→      <div className="grid grid-cols-1 md:grid-cols-3 border-t" style={{ borderColor: "#e8e8e5" }}>
   388→        <SourcesSection projectId={project.id} />
   389→        <RecentReleasesSection projectId={project.id} />
   390→        <SemanticReleasesSection projectId={project.id} />
   391→      </div>
