    58→              <SelectContent>
    59→                <SelectItem value="documentation">Documentation</SelectItem>
    60→                <SelectItem value="changelog">Changelog</SelectItem>
    61→                <SelectItem value="github_issues">GitHub Issues</SelectItem>
    62→                <SelectItem value="custom">Custom</SelectItem>
    63→              </SelectContent>
    64→            </Select>
    65→          </div>
    66→          <div className="space-y-2">
