    34→function formatDuration(startedAt?: string, completedAt?: string): string {
    35→  if (!startedAt) return "--";
    36→  const start = new Date(startedAt).getTime();
    37→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    38→  const secs = Math.round((end - start) / 1000);
    39→  if (secs < 60) return `${secs}s`;
    40→  const mins = Math.floor(secs / 60);
    41→  const rem = secs % 60;
    42→  return `${mins}m ${rem}s`;
    43→}
    44→
    45→function truncate(str: string, max: number): string {
    46→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    47→}
    48→
    49→function formatInterval(seconds: number): string {
    50→  if (seconds < 60) return `${seconds}s`;
    51→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    52→  return `${(seconds / 3600).toFixed(1)}h`;
    53→}
